<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Kanban Board</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      background: #f4f5f7;
      min-height: 100vh;
      padding: 24px;
    }
    .board {
      display: flex;
      gap: 16px;
      max-width: 1200px;
      margin: 0 auto 24px;
      height: calc(100vh - 120px);
      min-height: 500px;
    }
    .column {
      flex: 1;
      background: #ebecf0;
      border-radius: 12px;
      display: flex;
      flex-direction: column;
      min-width: 0;
    }
    .column-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 16px 20px;
      font-weight: 600;
      font-size: 14px;
      text-transform: uppercase;
      letter-spacing: 0.5px;
      color: #172b4d;
    }
    .column-header .count {
      background: #0052cc;
      color: white;
      font-size: 12px;
      font-weight: 600;
      padding: 2px 8px;
      border-radius: 12px;
      min-width: 24px;
      text-align: center;
    }
    .card-container {
      flex: 1;
      overflow-y: auto;
      padding: 0 12px 12px;
      display: flex;
      flex-direction: column;
      gap: 8px;
      min-height: 100px;
    }
    .card-container.drag-over {
      background: rgba(0, 82, 204, 0.1);
      border-radius: 8px;
    }
    .card {
      background: white;
      border-radius: 8px;
      padding: 12px 14px;
      box-shadow: 0 1px 2px rgba(9, 30, 66, 0.15);
      cursor: grab;
      display: flex;
      align-items: flex-start;
      justify-content: space-between;
      gap: 12px;
      transition: box-shadow 0.15s ease, transform 0.15s ease;
      user-select: none;
    }
    .card:hover {
      box-shadow: 0 4px 8px rgba(9, 30, 66, 0.15);
      transform: translateY(-1px);
    }
    .card:active, .card.dragging {
      cursor: grabbing;
      box-shadow: 0 8px 16px rgba(9, 30, 66, 0.2);
      transform: translateY(-2px);
    }
    .card.dragging {
      opacity: 0.5;
    }
    .card-title {
      flex: 1;
      font-size: 14px;
      line-height: 1.4;
      color: #172b4d;
      word-break: break-word;
      padding-right: 8px;
    }
    .card-del {
      flex-shrink: 0;
      width: 24px;
      height: 24px;
      border: none;
      background: transparent;
      color: #6b778c;
      font-size: 18px;
      line-height: 1;
      cursor: pointer;
      border-radius: 4px;
      display: flex;
      align-items: center;
      justify-content: center;
      transition: background 0.15s ease, color 0.15s ease;
      margin-top: -2px;
    }
    .card-del:hover {
      background: #ffebe9;
      color: #de350b;
    }
    .add-card-form {
      max-width: 1200px;
      margin: 0 auto;
      display: flex;
      gap: 12px;
    }
    #new-card {
      flex: 1;
      padding: 12px 16px;
      border: 2px solid #dfe1e6;
      border-radius: 8px;
      font-size: 14px;
      font-family: inherit;
      outline: none;
      transition: border-color 0.15s ease, box-shadow 0.15s ease;
    }
    #new-card:focus {
      border-color: #0052cc;
      box-shadow: 0 0 0 3px rgba(0, 82, 204, 0.15);
    }
    #add-card {
      padding: 12px 24px;
      background: #0052cc;
      color: white;
      border: none;
      border-radius: 8px;
      font-size: 14px;
      font-weight: 600;
      font-family: inherit;
      cursor: pointer;
      transition: background 0.15s ease;
    }
    #add-card:hover {
      background: #0065ff;
    }
    #add-card:active {
      background: #0043a3;
    }
    @media (max-width: 768px) {
      .board { flex-direction: column; height: auto; min-height: auto; }
      .column { min-height: 200px; }
    }
  </style>
</head>
<body>
  <div class="board">
    <div id="col-todo" class="column" data-column="todo">
      <div class="column-header">
        <h2>To Do</h2>
        <span class="count">0</span>
      </div>
      <div class="card-container"></div>
    </div>
    <div id="col-doing" class="column" data-column="doing">
      <div class="column-header">
        <h2>Doing</h2>
        <span class="count">0</span>
      </div>
      <div class="card-container"></div>
    </div>
    <div id="col-done" class="column" data-column="done">
      <div class="column-header">
        <h2>Done</h2>
        <span class="count">0</span>
      </div>
      <div class="card-container"></div>
    </div>
  </div>
  <div class="add-card-form">
    <input type="text" id="new-card" placeholder="Enter card title...">
    <button id="add-card">Add Card</button>
  </div>

  <script>
    (function() {
      const STORAGE_KEY = 'kanban-board-state';
      let cardIdCounter = 0;
      let draggedCard = null;

      const columns = {
        todo: document.getElementById('col-todo'),
        doing: document.getElementById('col-doing'),
        done: document.getElementById('col-done')
      };

      const containers = {
        todo: columns.todo.querySelector('.card-container'),
        doing: columns.doing.querySelector('.card-container'),
        done: columns.done.querySelector('.card-container')
      };

      const counts = {
        todo: columns.todo.querySelector('.count'),
        doing: columns.doing.querySelector('.count'),
        done: columns.done.querySelector('.count')
      };

      function generateId() {
        return 'card-' + Date.now() + '-' + (++cardIdCounter);
      }

      function saveState() {
        const state = {};
        Object.keys(containers).forEach(col => {
          state[col] = Array.from(containers[col].querySelectorAll('.card')).map(card => ({
            id: card.dataset.id,
            title: card.querySelector('.card-title').textContent
          }));
        });
        localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
      }

      function loadState() {
        const data = localStorage.getItem(STORAGE_KEY);
        if (!data) return;
        try {
          const state = JSON.parse(data);
          Object.keys(state).forEach(col => {
            state[col].forEach(cardData => {
              createCardElement(cardData.title, col, cardData.id);
            });
          });
          updateAllCounts();
        } catch (e) {
          console.error('Failed to parse board state:', e);
        }
      }

      function createCardElement(title, columnKey, id = null) {
        const card = document.createElement('div');
        card.className = 'card';
        card.draggable = true;
        card.dataset.id = id || generateId();
        card.dataset.column = columnKey;

        const titleEl = document.createElement('span');
        titleEl.className = 'card-title';
        titleEl.textContent = title;

        const delBtn = document.createElement('button');
        delBtn.className = 'card-del';
        delBtn.innerHTML = '×';
        delBtn.setAttribute('aria-label', 'Delete card');
        delBtn.addEventListener('click', (e) => {
          e.stopPropagation();
          card.remove();
          updateCount(columnKey);
          saveState();
        });

        card.appendChild(titleEl);
        card.appendChild(delBtn);

        card.addEventListener('dragstart', handleDragStart);
        card.addEventListener('dragend', handleDragEnd);

        containers[columnKey].appendChild(card);
        updateCount(columnKey);
        return card;
      }

      function handleDragStart(e) {
        draggedCard = this;
        this.classList.add('dragging');
        e.dataTransfer.effectAllowed = 'move';
        e.dataTransfer.setData('text/plain', this.dataset.id);
      }

      function handleDragEnd(e) {
        this.classList.remove('dragging');
        document.querySelectorAll('.card-container.drag-over').forEach(c => c.classList.remove('drag-over'));
        draggedCard = null;
      }

      function handleDragOver(e) {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';
        const container = this.closest('.card-container');
        if (container) container.classList.add('drag-over');
      }

      function handleDragLeave(e) {
        const container = this.closest('.card-container');
        if (container && !container.contains(e.relatedTarget)) {
          container.classList.remove('drag-over');
        }
      }

      function handleDrop(e) {
        e.preventDefault();
        const container = this.closest('.card-container');
        if (!container || !draggedCard) return;

        container.classList.remove('drag-over');
        const targetColumn = container.parentElement.dataset.column;
        const sourceColumn = draggedCard.dataset.column;

        if (sourceColumn !== targetColumn) {
          draggedCard.dataset.column = targetColumn;
          container.appendChild(draggedCard);
          updateCount(sourceColumn);
          updateCount(targetColumn);
          saveState();
        }
      }

      function updateCount(columnKey) {
        const count = containers[columnKey].querySelectorAll('.card').length;
        counts[columnKey].textContent = count;
      }

      function updateAllCounts() {
        Object.keys(counts).forEach(updateCount);
      }

      // Initialize drag handlers on containers
      Object.values(containers).forEach(container => {
        container.addEventListener('dragover', handleDragOver);
        container.addEventListener('dragleave', handleDragLeave);
        container.addEventListener('drop', handleDrop);
      });

      // Add card button
      const newCardInput = document.getElementById('new-card');
      const addCardBtn = document.getElementById('add-card');

      addCardBtn.addEventListener('click', () => {
        const title = newCardInput.value.trim();
        if (title) {
          createCardElement(title, 'todo');
          newCardInput.value = '';
          saveState();
        }
      });

      newCardInput.addEventListener('keydown', (e) => {
        if (e.key === 'Enter') {
          addCardBtn.click();
        }
      });

      // Load persisted state
      loadState();
    })();
  </script>
</body>
</html>
